#include <iostream>

class Accumulator
{
private:
    int m_total{ 0 };

public:
    int operator()(int value)
    {
        m_total += value;
        return m_total;
    }
};

int main()
{
    int n{};
    std::cin >> n;

    Accumulator acc{};
    for (int i{ 0 }; i < n; ++i)
    {
        int value{};
        std::cin >> value;
        std::cout << acc(value) << '\n';
    }

    return 0;
}

